export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      i++
    } else if (arg.includes('=')) {
      // --key=value syntax
      const eqIndex = arg.indexOf('=')
      const key = arg.slice(2, eqIndex)
      result[key] = arg.slice(eqIndex + 1)
      i++
    } else {
      // --key value syntax - check if next arg is also a flag
      const key = arg.slice(2)
      const next = argv[i + 1]
      if (next && !next.startsWith('--')) {
        result[key] = next
        i += 2
      } else {
        result[key] = true
        i++
      }
    }
  }
  return result
}
